import React from 'react';
import { Card, Stack, Divider, Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const { city, temperature, condition, humidity, windSpeed, unit, forecast } = props;
  const tempUnit = unit ?? '°C';

  return (
    <Card 
      padding={24} 
      radius="xl" 
      shadow="md" 
      aria-label={`Weather report for ${city}`}
    >
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={2}>{city}</Heading>
          <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">
            {temperature}{tempUnit}
          </Text>
        </Stack>

        <Stack gap={4}>
          <Heading level={4}>{condition}</Heading>
          <Stack direction="horizontal" gap={16}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Humidity: {humidity}%
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Wind: {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

        <div role="region" aria-label="5-day forecast">
          <Stack direction="horizontal" justify="between" gap={8} wrap={true}>
            {forecast.map((item, i) => (
              <Stack align="center" gap={8} key={i}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.day ?? 'N/A'}
                </Text>
                <Text size="2xl">{item.icon ?? '?'}</Text>
                <Text variant="bodySmall">
                  {item.high ?? 0}° / {item.low ?? 0}°
                </Text>
              </Stack>
            ))}
          </Stack>
        </div>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Stack, Box, Text, Heading, Card } from '@ggui-ai/design/primitives';
import { Input, Badge } from '@ggui-ai/design/components';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-primary-100)',
  'noble-gas': 'var(--ggui-color-info-100)',
  'nonmetal': 'var(--ggui-color-success-100)',
  'transition-metal': 'var(--ggui-color-warning-50)',
  'other': 'var(--ggui-color-surfaceVariant)',
};

export default function GeneratedComponent({ elements }: Props) {
  const [query, setQuery] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);

  const filtered = useMemo(() => {
    if (!query) return elements;
    return elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(query.toLowerCase()) ||
        e.symbol?.toLowerCase().includes(query.toLowerCase())
    );
  }, [elements, query]);

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        <Heading level={1}>Periodic Table</Heading>

        <Box background="var(--ggui-color-surface)" padding={16} borderRadius="md">
          <Input 
            label="Search Elements" 
            placeholder="Search by name or symbol..." 
            value={query} 
            onChange={setQuery} 
          />
        </Box>

        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, minmax(50px, 1fr))',
          gap: 'var(--ggui-spacing-1)',
          overflowX: 'auto'
        }}>
          {elements.map((el, i) => {
            const isMatch = filtered.includes(el);
            const category = el.category ?? 'other';
            const bg = CATEGORY_COLORS[category] ?? CATEGORY_COLORS['other'];

            return (
              <button
                key={i}
                onClick={() => setSelected(el)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  padding: 'var(--ggui-spacing-2)',
                  backgroundColor: isMatch ? bg : 'var(--ggui-color-surfaceVariant)',
                  border: `1px solid ${selected === el ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outlineVariant)'}`,
                  borderRadius: 'var(--ggui-shape-radius-sm)',
                  cursor: 'pointer',
                  textAlign: 'left',
                  transition: 'background-color 200ms ease-in-out',
                  opacity: isMatch ? 1 : 0.3
                }}
              >
                <Text variant="caption">{el.atomicNumber ?? ''}</Text>
                <Heading level={3} align="center">{el.symbol ?? ''}</Heading>
              </button>
            );
          })}
        </div>

        {selected && (
          <Card shadow="md" padding={24}>
            <Stack gap={12}>
              <Heading level={2}>{selected.name}</Heading>
              <Stack direction="horizontal" gap={16}>
                <Text>Symbol: <strong>{selected.symbol}</strong></Text>
                <Text>Atomic Number: <strong>{selected.atomicNumber}</strong></Text>
                <Text>Atomic Weight: <strong>{selected.atomicWeight}</strong></Text>
              </Stack>
              <Badge variant="primary">{selected.category}</Badge>
            </Stack>
          </Card>
        )}

        <Card padding={16}>
          <Heading level={4}>Legend</Heading>
          <Stack direction="horizontal" gap={8} wrap>
            {Object.entries(CATEGORY_COLORS).map(([cat, color]) => (
              <Box key={cat} padding={8} background={color} borderRadius="sm">
                <Text variant="caption">{cat}</Text>
              </Box>
            ))}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Divider, Text, Heading, Spacer } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const unitLabel = props.unit ?? 'C';

  return (
    <Card shadow="md" padding="24px" radius="xl" border={true}>
      <Stack direction="vertical" gap="24px" align="stretch">
        {/* Header Section */}
        <Stack direction="vertical" align="center" gap="4px">
          <Heading level={3}>{props.city}</Heading>
          <Text variant="bodyLarge" color="var(--ggui-color-neutral-500, #6b7280)">
            {props.condition}
          </Text>
        </Stack>

        {/* Hero Section */}
        <Stack direction="vertical" align="center" gap="8px">
          <Heading level={1} color="var(--ggui-color-primary-600, #0284c7)">
            {props.temperature}°{unitLabel}
          </Heading>
        </Stack>

        {/* Metrics Strip */}
        <Stack direction="horizontal" justify="between" align="center" gap="16px">
          <Stack direction="vertical" align="center" gap="4px">
            <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Humidity</Text>
            <Text variant="body">{props.humidity}%</Text>
          </Stack>
          <Stack direction="vertical" align="center" gap="4px">
            <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Wind</Text>
            <Text variant="body">{props.windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider orientation="horizontal" margin="0" />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between" align="center" gap="8px">
          {props.forecast.map((item, index) => (
            <Stack key={index} direction="vertical" align="center" gap="8px" style={{ flex: 1 }}>
              <Text variant="caption">{item.day ?? '—'}</Text>
              <Text size="xl">{item.icon ?? '☁️'}</Text>
              <Stack direction="vertical" align="center" gap="0px">
                <Text variant="label" weight="semibold">
                  {item.high ?? '—'}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                  {item.low ?? '—'}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Container, Card, Stack, Box, Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function GeneratedComponent(props: Props) {
  const [filter, setFilter] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const getCategoryColor = (category?: string) => {
    switch (category) {
      case 'noble-gas': return 'var(--ggui-color-info-200)';
      case 'nonmetal': return 'var(--ggui-color-success-200)';
      case 'halogen': return 'var(--ggui-color-warning-200)';
      case 'alkali-metal': return 'var(--ggui-color-primary-200)';
      default: return 'var(--ggui-color-neutral-100)';
    }
  };

  const filteredElements = useMemo(() => {
    const q = filter.toLowerCase();
    return props.elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(q) ||
        e.symbol?.toLowerCase().includes(q)
    );
  }, [props.elements, filter]);

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        <Heading level={2}>Periodic Table</Heading>

        <Box paddingY={16}>
          <input
            type="search"
            placeholder="Search by name or symbol..."
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
            style={{
              width: '100%',
              padding: 'var(--ggui-spacing-2, 8px)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              border: '1px solid var(--ggui-color-neutral-300, #d1d5db)',
              fontSize: 'var(--ggui-font-size-base, 16px)'
            }}
          />
        </Box>

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)'
          }}
        >
          {filteredElements.map((el, i) => (
            <Card
              key={`${el.atomicNumber}-${i}`}
              shadow="sm"
              padding={4}
              radius="sm"
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                backgroundColor: getCategoryColor(el.category),
                cursor: 'pointer',
                transition: 'background-color 200ms ease'
              }}
              onClick={() => setSelectedElement(el)}
            >
              <Stack gap={0} align="center">
                <Text variant="caption">{el.atomicNumber}</Text>
                <Text variant="label" weight="bold">{el.symbol}</Text>
              </Stack>
            </Card>
          ))}
        </Box>

        <Card shadow="md" padding={16}>
          <Heading level={3}>Element Details</Heading>
          {selectedElement ? (
            <Stack gap={8}>
              <Text variant="bodyLarge">{selectedElement.name} ({selectedElement.symbol})</Text>
              <Text variant="bodySmall">Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text variant="bodySmall">Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text variant="bodySmall">Category: {selectedElement.category}</Text>
            </Stack>
          ) : (
            <Text variant="caption" color="var(--ggui-color-neutral-500)">Select an element to see details</Text>
          )}
        </Card>
      </Stack>
    </Container>
  );
}
